const labels = {"nr32": "NR 32", "nr06": "NR 06", "ginastica_nr17": "Ginástica Laboral / NR 17", "dis001_atestados": "Atestados - DIS 001", "dis002_acidentes": "Acidentes - DIS 002", "anti_tabagismo": "Anti-tabagismo - DIS 062", "quedas": "Prevenção de Quedas", "junho_vermelho": "Junho Vermelho", "assedio": "Assédio e Violência", "misto": "Misto Geral"};
const emojis = {"nr32": "🧪", "nr06": "🦺", "ginastica_nr17": "🤸", "dis001_atestados": "📄", "dis002_acidentes": "🚨", "anti_tabagismo": "🚭", "quedas": "⚠️", "junho_vermelho": "🩸", "assedio": "🤝", "misto": "🎯"};
const $ = (id) => document.getElementById(id);
const els = {
  startScreen: $('startScreen'), gameScreen: $('gameScreen'), resultScreen: $('resultScreen'),
  playerName: $('playerName'), categoryGrid: $('categoryGrid'), amountGrid: $('amountGrid'),
  selectedCategoryLabel: $('selectedCategoryLabel'), bestScore: $('bestScore'), startBtn: $('startBtn'),
  currentPlayer: $('currentPlayer'), score: $('score'), timer: $('timer'), timerRing: $('timerRing'),
  questionCount: $('questionCount'), questionTag: $('questionTag'), progressBar: $('progressBar'), questionText: $('questionText'),
  answers: $('answers'), feedback: $('feedback'), explanation: $('explanation'), nextBtn: $('nextBtn'),
  resultTitle: $('resultTitle'), resultText: $('resultText'), correctTotal: $('correctTotal'), wrongTotal: $('wrongTotal'),
  finalBest: $('finalBest'), resultNote: $('resultNote'), restartBtn: $('restartBtn'), changeCategoryBtn: $('changeCategoryBtn')
};

let selectedCategory = 'nr32';
let selectedAmount = '20';
let currentQuestions = [];
let index = 0, score = 0, correct = 0, wrong = 0, timer = 25, timerInterval = null, answered = false;
const letters = ['A','B','C','D'];

function getPlayableCategories() {
  return Object.keys(labels).filter(k => k !== 'misto').concat('misto');
}

function getBestKey() {
  return `desafio_sst_quiz_${selectedCategory}_${selectedAmount}`;
}

function updateBestScore() {
  els.bestScore.textContent = localStorage.getItem(getBestKey()) || '0';
}

function updateSummary() {
  els.selectedCategoryLabel.textContent = labels[selectedCategory];
  updateBestScore();
}

function buildCategoryCards() {
  els.categoryGrid.innerHTML = '';
  getPlayableCategories().forEach(key => {
    const btn = document.createElement('button');
    btn.className = `category-card ${key === selectedCategory ? 'active' : ''}`;
    btn.innerHTML = `<span class="category-icon">${emojis[key] || '🎯'}</span><span class="category-title">${labels[key]}</span>`;
    btn.onclick = () => {
      selectedCategory = key;
      buildCategoryCards();
      updateSummary();
    };
    els.categoryGrid.appendChild(btn);
  });
}

function initAmountPills() {
  [...els.amountGrid.querySelectorAll('.amount-pill')].forEach(btn => {
    btn.onclick = () => {
      selectedAmount = btn.dataset.amount;
      [...els.amountGrid.querySelectorAll('.amount-pill')].forEach(b => b.classList.toggle('active', b === btn));
      updateBestScore();
    };
  });
}

function shuffle(arr) {
  return [...arr].sort(() => Math.random() - 0.5);
}

function prepareQuestionForRound(question) {
  const options = shuffle(
    question.a.map((text, originalIndex) => ({ text, originalIndex }))
  );

  return {
    ...question,
    options,
    correctIndex: options.findIndex(option => option.originalIndex === question.correct)
  };
}

function questionId(question) {
  return `${question.tag}::${question.q}`;
}

function getQuestionFrequencyMap() {
  try {
    return JSON.parse(localStorage.getItem(`desafio_sst_freq_${selectedCategory}`) || '{}');
  } catch (error) {
    return {};
  }
}

function saveQuestionFrequencyMap(map) {
  localStorage.setItem(`desafio_sst_freq_${selectedCategory}`, JSON.stringify(map));
}

function pickBalancedQuestions(pool, total) {
  const frequency = getQuestionFrequencyMap();

  const grouped = {};
  pool.forEach(question => {
    const count = frequency[questionId(question)] || 0;
    if (!grouped[count]) grouped[count] = [];
    grouped[count].push(question);
  });

  const selected = [];
  Object.keys(grouped)
    .map(Number)
    .sort((a, b) => a - b)
    .forEach(count => {
      selected.push(...shuffle(grouped[count]));
    });

  const finalList = selected.slice(0, total);

  finalList.forEach(question => {
    const id = questionId(question);
    frequency[id] = (frequency[id] || 0) + 1;
  });
  saveQuestionFrequencyMap(frequency);

  return finalList;
}

function totalQuestionsForRun() {
  const available = questions[selectedCategory].length;
  return selectedAmount === 'all' ? available : Math.min(Number(selectedAmount), available);
}

function startGame() {
  currentQuestions = pickBalancedQuestions(questions[selectedCategory], totalQuestionsForRun())
    .map(prepareQuestionForRound);
  index = 0; score = 0; correct = 0; wrong = 0;
  els.currentPlayer.textContent = els.playerName.value.trim() || 'Participante';
  els.startScreen.classList.add('hidden');
  els.resultScreen.classList.add('hidden');
  els.gameScreen.classList.remove('hidden');
  loadQuestion();
}

function loadQuestion() {
  answered = false;
  els.nextBtn.classList.add('hidden');
  els.feedback.textContent = '';
  els.feedback.className = 'feedback';
  els.explanation.textContent = '';
  els.explanation.classList.add('hidden');
  els.answers.innerHTML = '';
  const item = currentQuestions[index];
  els.questionCount.textContent = `Pergunta ${index + 1}/${currentQuestions.length}`;
  els.questionTag.textContent = item.tag;
  els.questionText.textContent = item.q;
  els.progressBar.style.width = `${(index / currentQuestions.length) * 100}%`;
  els.score.textContent = score;

  item.options.forEach((option, i) => {
    const btn = document.createElement('button');
    btn.className = 'answer';
    btn.innerHTML = `<span class="answer-badge">${letters[i]}</span><span class="answer-text">${option.text}</span>`;
    btn.onclick = () => chooseAnswer(i);
    els.answers.appendChild(btn);
  });

  startTimer();
}

function renderTimerRing() {
  const pct = Math.max(0, (timer / 25) * 100);
  els.timerRing.style.background = `conic-gradient(var(--yellow) ${pct}%, rgba(255,255,255,.08) 0)`;
  els.timer.textContent = timer;
}

function startTimer() {
  clearInterval(timerInterval);
  timer = 25;
  renderTimerRing();
  timerInterval = setInterval(() => {
    timer--;
    renderTimerRing();
    if (timer <= 0) chooseAnswer(null);
  }, 1000);
}

function chooseAnswer(answerIndex) {
  if (answered) return;
  answered = true;
  clearInterval(timerInterval);

  const item = currentQuestions[index];
  const buttons = [...document.querySelectorAll('.answer')];

  buttons.forEach((btn, i) => {
    btn.disabled = true;
    if (i === item.correctIndex) btn.classList.add('correct');
  });

  if (answerIndex === item.correctIndex) {
    const points = 100 + timer * 2;
    score += points;
    correct++;
    els.feedback.textContent = `✅ Acertou! +${points} pontos`;
    els.feedback.classList.add('ok');
  } else {
    wrong++;
    if (answerIndex !== null && buttons[answerIndex]) buttons[answerIndex].classList.add('wrong');
    els.feedback.textContent = answerIndex === null ? '⏰ Tempo esgotado!' : '❌ Errou!';
    els.feedback.classList.add('bad');
  }

  els.explanation.textContent = item.exp;
  els.explanation.classList.remove('hidden');
  els.score.textContent = score;
  els.nextBtn.classList.remove('hidden');
}

function nextQuestion() {
  index++;
  if (index >= currentQuestions.length) finishGame();
  else loadQuestion();
}

function finishGame() {
  clearInterval(timerInterval);
  els.progressBar.style.width = '100%';

  const oldBest = Number(localStorage.getItem(getBestKey()) || 0);
  const newBest = Math.max(oldBest, score);
  localStorage.setItem(getBestKey(), String(newBest));

  els.gameScreen.classList.add('hidden');
  els.resultScreen.classList.remove('hidden');

  const pct = Math.round((correct / currentQuestions.length) * 100);
  els.resultTitle.textContent = score >= oldBest && score > 0 ? 'Novo recorde!' : 'Fim do quiz!';
  els.resultText.textContent = `${els.currentPlayer.textContent}, você fez ${score} pontos em ${labels[selectedCategory]}.`;
  els.correctTotal.textContent = correct;
  els.wrongTotal.textContent = wrong;
  els.finalBest.textContent = newBest;
  els.resultNote.textContent = pct >= 80 ? 'Mandou muito bem! Esse resultado ficou digno de campeão.' : pct >= 50 ? 'Foi bem! Mais uma rodada e você pode bater o recorde.' : 'Bora jogar de novo e melhorar a pontuação.';

  updateBestScore();
}

function backToStart() {
  clearInterval(timerInterval);
  els.resultScreen.classList.add('hidden');
  els.gameScreen.classList.add('hidden');
  els.startScreen.classList.remove('hidden');
  updateBestScore();
}

els.startBtn.onclick = startGame;
els.nextBtn.onclick = nextQuestion;
els.restartBtn.onclick = startGame;
els.changeCategoryBtn.onclick = backToStart;

buildCategoryCards();
initAmountPills();
updateSummary();
